+fn test_envelope(
+    payload: &[u8],
+    object_n: u8,
+    epoch_id: u64,
+    retention: RetentionClass,
+) -> ControlPlaneEnvelope {
+    ControlPlaneEnvelope::new(
+        payload.to_vec(),
+        [0xAA; 32],
+        test_object_id(object_n),
+        test_zone(),
+        test_zone_key_id(),
+        epoch_id,
+        retention,
+    )
+}
+
+#[test]
+fn retention_class_default_is_required() {
+    assert_eq!(RetentionClass::default(), RetentionClass::Required);
+}
