+fn make_tokens(access_token: &str, expires_in: Option<u64>) -> OAuthTokens {
+    OAuthTokens::from_response(TokenResponse {
+        access_token: access_token.to_string(),
+        token_type: "Bearer".to_string(),
+        expires_in,
+        refresh_token: None,
+        scope: None,
+        id_token: None,
+    })
+}
