+        (
+            SupplyChainVerificationError::TufTargetNotFound {
+                target: "fcp.test".into(),
+            },
+            "fcp.test",
+        ),
+        (
+            SupplyChainVerificationError::TufRollback {
+                current: 5,
+                got: 3,
+            },
+            "rollback",
+        ),
